import { TestingModule } from '@nestjs/testing';
import { DataSource, Repository } from 'typeorm';
import { createIntegrationTestModule, cleanDatabase } from './setup';
import { Refund } from '../../src/entities/refund.entity';
import { buildRefund } from '../factories/refund.factory';
import { Payment } from '../../src/entities/payment.entity';
import { buildPayment } from '../factories/payment.factory';

describe('Refund Relationships', () => {
  let module: TestingModule;
  let dataSource: DataSource;
  let repository: Repository<Refund>;
  let paymentId: string;

  beforeAll(async () => {
    module = await createIntegrationTestModule();
    dataSource = module.get(DataSource);
    repository = dataSource.getRepository(Refund);
  });

  beforeEach(async () => {
    const paymentEntity = await dataSource
      .getRepository(Payment)
      .save(
        dataSource.getRepository(Payment).create(
          buildPayment(),
        ),
      );
    paymentId = paymentEntity.id;
  });

  afterEach(async () => {
    await cleanDatabase(dataSource);
  });

  afterAll(async () => {
    await module.close();
  });

  describe('belongs_to Payment', () => {
    it('persists paymentId reference', async () => {
      const data = buildRefund({ paymentId: paymentId });
      const saved = await repository.save(repository.create(data));
      expect(saved.paymentId).toBe(paymentId);
    });

    it('loads parent via relation', async () => {
      const data = buildRefund({ paymentId: paymentId });
      const saved = await repository.save(repository.create(data));
      const loaded = await repository.findOne({
        where: { id: saved.id } as Record<string, unknown>,
        relations: ['payment'],
      });
      expect(loaded).not.toBeNull();
      expect(loaded!.payment).toBeDefined();
      expect(loaded!.payment.id).toBe(paymentId);
    });

    it('rejects entity without required paymentId', async () => {
      const data = buildRefund({ paymentId: undefined as unknown as string });
      await expect(
        repository.save(repository.create(data)),
      ).rejects.toThrow();
    });
  });
});
